const input = $('Set Input').first().json;
const prompt = $input.first().json;

let userPrompt = prompt.user_prompt_template;
userPrompt = userPrompt.replace('{{topic}}', input.topic);
userPrompt = userPrompt.replace('{{context}}', input.context || '');

return [{
  json: {
    system_prompt: prompt.system_prompt,
    user_prompt: userPrompt,
    topic: input.topic,
    pillar: input.pillar,
    content_type: input.content_type
  }
}];

const ollamaResponse = $input.first().json;
const preparedData = $('Prepare Prompt').first().json;

const content = ollamaResponse.message?.content || 'Generation failed - no content returned';

return [{
  json: {
    title: preparedData.topic,
    platform: 'linkedin',
    pillar: preparedData.pillar,
    content_type: preparedData.content_type,
    generated_content: content,
    status: 'pending_review'
  }
}];

